class Solution:
    def minimumObstacles(self, grid: List[List[int]]) -> int:
        pq=[(0,0,0)]
        visited=set()
        m=len(grid)
        n=len(grid[0])

        cost_matrix = [[float('inf')] * n for _ in range(m)]
        cost_matrix[0][0]=0

        directions=[(1,0),(0,1),(-1,0),(0,-1)]

        while(pq):
            cost,x,y=heapq.heappop(pq)
            if (x,y) in visited:
                continue

            visited.add((x,y))

            if x==m-1 and y==n-1:
                return cost
            for dx,dy in directions:
                if(0<=x+dx<=m-1 and 0<=y+dy<=n-1):
                    new_cost=cost+grid[x+dx][y+dy]
                    if(new_cost<cost_matrix[x+dx][y+dy]):
                        heapq.heappush(pq,(cost+grid[x+dx][y+dy],x+dx,y+dy))
                        cost_matrix[x+dx][y+dy]=new_cost

        return -1

class MergeSort:
    def sort(self, array):
        if not array:
            return
        self.merge_sort(array, 0, len(array) - 1)

    def merge_sort(self, array, left, right):
        if left < right:
            mid = left + (right - left) // 2
            self.merge_sort(array, left, mid)
            self.merge_sort(array, mid + 1, right)
            self.merge(array, left, mid, right)

    def merge(self, array, left, mid, right):
        n1 = mid - left + 1
        n2 = right - mid

        left_array = array[left:left + n1]
        right_array = array[mid + 1:mid + 1 + n2]

        i = j = 0
        k = left

        while i < n1 and j < n2:
            if left_array[i] <= right_array[j]:
                array[k] = left_array[i]
                i += 1
            else:
                array[k] = right_array[j]
                j += 1
            k += 1

        while i < n1:
            array[k] = left_array[i]
            i += 1
            k += 1

        while j < n2:
            array[k] = right_array[j]
            j += 1
            k += 1

