class Solution:
    def restoreIpAddresses(self, s: str) -> list[str]:
        def backtrack(ips, s, i, dots, curr):
            if dots == 4 and i == len(s):
                ips.append(curr[:-1])
                return
            if dots > 4:
                return
            for j in range(i, min(i + 3, len(s))):
                seg = s[i:j + 1]
                if int(seg) <= 255 and (i == j or s[i] != '0'):
                    backtrack(ips, s, j + 1, dots + 1, curr + seg + '.')

        ips = []
        if len(s) > 12:
            return ips
        backtrack(ips, s, 0, 0, "")
        return ips

