def max_profit(n, profit, weight, W):
    table = [[0] * (W + 1) for _ in range(n + 1)]

    for i in range(n + 1):
        for j in range(W + 1):
            if i == 0 or j == 0:
                table[i][j] = 0
            elif j - weight[i - 1] < 0:
                table[i][j] = table[i - 1][j]
            else:
                table[i][j] = max(table[i - 1][j], profit[i - 1] + table[i - 1][j - weight[i - 1]])

    return table[n][W]

