class RadixSort:
    def get_max(self, arr):
        max_elem = arr[0]
        for num in arr[1:]:
            max_elem = max(max_elem, num)
        return max_elem

    def counting_sort(self, arr, exp):
        n = len(arr)
        output = [0] * n
        count = [0] * 10

        for num in arr:
            count[(num // exp) % 10] += 1

        for i in range(1, 10):
            count[i] += count[i - 1]

        for i in range(n - 1, -1, -1):
            output[count[(arr[i] // exp) % 10] - 1] = arr[i]
            count[(arr[i] // exp) % 10] -= 1

        for i in range(n):
            arr[i] = output[i]

    def radix_sort(self, arr):
        max_elem = self.get_max(arr)
        exp = 1
        while max_elem // exp > 0:
            self.counting_sort(arr, exp)
            exp *= 10

