class Solution:
    def canFinish(self, numCourses, prerequisites):
        premap = {i: [] for i in range(numCourses)}
        visited = set()
        for x in prerequisites:
            premap[x[0]].append(x[1])

        for i in range(numCourses):
            if not self.dfs(i, visited, premap):
                return False
        return True

    def dfs(self, crs, visited, premap):
        if crs in visited:
            return False
        if not premap[crs]:
            return True
        visited.add(crs)
        for pre in premap[crs]:
            if not self.dfs(pre, visited, premap):
                return False
        visited.remove(crs)
        premap[crs] = []
        return True

