def build_bad_character_table(pattern: str) -> list[int]:
    m = len(pattern)
    bad_char_table = [m] * 256  # Initialize table with pattern length

    for i in range(m - 1):
        bad_char_table[ord(pattern[i])] = m - i - 1

    return bad_char_table

def horspool_search(text: str, pattern: str) -> int:
    n = len(text)
    m = len(pattern)

    if m == 0 or n < m:
        return -1

    bad_char_table = build_bad_character_table(pattern)
    i = m - 1

    while i < n:
        k = i
        j = m - 1

        while j >= 0 and text[k] == pattern[j]:
            k -= 1
            j -= 1

        if j < 0:
            return k + 1

        i += bad_char_table[ord(text[i])]

    return -1

class Knapsack:
    def __init__(self, n, W):
        self.memo = [[-1 for _ in range(W + 1)] for _ in range(n + 1)] 

    def knapsack_rec(self, n, W, values, weights):
        if n == 0 or W == 0:
            return 0
        if self.memo[n][W] != -1:
            return self.memo[n][W]

        if weights[n - 1] > W:
            self.memo[n][W] = self.knapsack_rec(n - 1, W, values, weights)
        else:
            exclude = self.knapsack_rec(n - 1, W, values, weights)
            include = values[n - 1] + self.knapsack_rec(n - 1, W - weights[n - 1], values, weights)
            self.memo[n][W] = max(exclude, include)

        return self.memo[n][W]

