                if len(stack) < 2:
                    raise ValueError("Invalid prefix expression.")
                operand1 = stack.pop()
                operand2 = stack.pop()
                result = self.apply_operator(c, operand1, operand2)
                stack.append(result)
            else:
                raise ValueError("Invalid character in the prefix expression.")

        if len(stack) != 1:
            raise ValueError("Invalid prefix expression.")

        return stack.pop()

    def apply_operator(self, op, operand1, operand2):
        if op == '+':
            return operand1 + operand2
        elif op == '-':
            return operand1 - operand2
        elif op == '*':
            return operand1 * operand2
        elif op == '/':
            return operand1 / operand2
        elif op == '^':
            return math.pow(operand1, operand2)
        else:
            raise ValueError("Unknown operator.")

