            'V': 5,
            'X': 10,
            'L': 50,
            'C': 100,
            'D': 500,
            'M': 1000
        }

        # Iterate through each character in the Roman numeral string
        for i in range(len(s)):
            # If the current numeral is smaller than the next one, subtract it
            if i < len(s) - 1 and hashmap[s[i]] < hashmap[s[i + 1]]:
