class Solution:
    def __init__(self):
        self.directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    
    def minimumObstacles(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        minObstacles = [[float('inf')] * n for _ in range(m)]
        minObstacles[0][0] = 0
        dq = deque([(0, 0, 0)])
        
        while dq:
            obstacles, row, col = dq.popleft()
            for dir in self.directions:
                newRow, newCol = row + dir[0], col + dir[1]
                if self.isValid(grid, newRow, newCol) and minObstacles[newRow][newCol] == float('inf'):
                    if grid[newRow][newCol] == 1:
                        minObstacles[newRow][newCol] = obstacles + 1
                        dq.append((obstacles + 1, newRow, newCol))
                    else:
                        minObstacles[newRow][newCol] = obstacles
                        dq.appendleft((obstacles, newRow, newCol))
        
        return minObstacles[m - 1][n - 1]
    
    def isValid(self, grid, row, col):
        return 0 <= row < len(grid) and 0 <= col < len(grid[0])

class Solution:
    def __init__(self):
        self.minMinutes = float('inf')

    def takeCharacters(self, s: str, k: int) -> int:
        if k == 0:
            return 0
        count = [0, 0, 0]
        self.solve(s, k, 0, len(s) - 1, count, 0)
        return -1 if self.minMinutes == float('inf') else self.minMinutes

    def solve(self, s, k, left, right, count, minutes):
        if count[0] >= k and count[1] >= k and count[2] >= k:
            self.minMinutes = min(self.minMinutes, minutes)
            return
        if left > right:
            return
        leftCount = count[:]
        leftCount[ord(s[left]) - ord('a')] += 1
        self.solve(s, k, left + 1, right, leftCount, minutes + 1)
        rightCount = count[:]
        rightCount[ord(s[right]) - ord('a')] += 1
        self.solve(s, k, left, right - 1, rightCount, minutes + 1)

