def rabinKarpSearch(text: str, pattern: str) -> bool:
    if len(pattern) > len(text):
        return False

    patternHash = computeRollingHash(pattern, 0, len(pattern))
    textHash = computeRollingHash(text, 0, len(pattern))

    for i in range(len(text) - len(pattern) + 1):
        if patternHash == textHash:
            match = True
            for j in range(len(pattern)):
                if text[i + j] != pattern[j]:
                    match = False
                    break
            if match:
                return True

        if i < len(text) - len(pattern):
            textHash = (textHash - ord(text[i]) * pow(31, len(pattern) - 1)) * 31 + ord(text[i + len(pattern)])

    return False

def computePolynomialCoefficient(n: int, k: int) -> int:
    if k > n:
        return 0

    dp = [[0] * (k + 1) for _ in range(n + 1)]

    for i in range(n + 1):
        dp[i][0] = 1

    for i in range(1, n + 1):
        for j in range(1, min(i, k) + 1):
            dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j]

    return dp[n][k]

